//! train_amp_v2 — Phase B of the AmplituhedronAttentionV2 plan.
//!
//! Trains a 1-layer toy character-level next-token model with two
//! interchangeable attention kernels and reports a head-to-head
//! perplexity comparison:
//!
//!   * V1 baseline — softmax(QK^T/√d) attention via
//!     `scattering_attention::attention_via_softmax`.
//!   * V2 amplituhedron — `attention_via_amplituhedron_v2` with a
//!     learned 2×2 `MixingBlock` (4 floats) + learned dual covector
//!     (length C(k_sub, 2) = 28). Identity mix at init reduces V2 to
//!     V1's CatQK row composition (Phase A parity test pins this byte-
//!     identically); training is what gates whether the asymmetric
//!     subspace gives a usable gradient signal.
//!
//! The whole program is intentionally a research smoke test:
//!   * No external ML / autodiff dep — gradients are estimated by
//!     central differences for the small param sets (MixingBlock = 4,
//!     dual = 28) and by SPSA (Spall, 1992) for the big projection
//!     matrices (V = d_head², lm_head = d_head·vocab). SPSA is a
//!     finite-difference *gradient estimator*: each step still uses
//!     `(loss(θ + ε·Δ) − loss(θ − ε·Δ)) / (2ε)`, just along a single
//!     random ±1 direction Δ instead of every standard basis vector,
//!     so the per-step cost is O(1) forward passes regardless of
//!     |θ|. This keeps wall clock under 60s at the spec dims; doing
//!     full per-parameter central diff over ~20 K params would need
//!     40 K forwards per step, which the spec budget does not buy.
//!     The mix block + dual ARE per-parameter — they're tiny and they
//!     are the parameters whose dynamics we actually care about.
//!   * No `rand` crate — all randomness comes from a SplitMix64 LCG
//!     seeded from a constant.
//!   * After every step the binary asserts
//!     `MixingBlock::is_asymmetric_in_qk()` so the `learned_mix_invariant`
//!     gate (Lean
//!     `open-source/gnosis-math/Gnosis/AmplituhedronAttentionV2Architecture.lean`,
//!     `learned_mix_invariant`) is observed empirically across the
//!     entire optimization trajectory, not just at init.
//!
//! Output (stdout):
//!   * `step k v1=loss v2=loss mix=⟨α,β,γ,δ⟩ asym=true|false`
//!   * Final perplexity table for V1 vs V2 on a held-out test split
//!   * Final MixingBlock + final dual covector
//!
//! Run:
//!   cargo run --release --bin train_amp_v2

use distributed_inference::scattering_amplitude::k_subsets;
use distributed_inference::scattering_attention::attention_via_softmax;
use distributed_inference::scattering_attention_v2::{attention_via_amplituhedron_v2, MixingBlock};

// ════════════════════════════════════════════════════════════════════
// MODEL HYPERPARAMETERS  (spec)
// ════════════════════════════════════════════════════════════════════

#[cfg(not(test))]
const VOCAB_SIZE: usize = 256;
#[cfg(test)]
const VOCAB_SIZE: usize = 128;

#[cfg(not(test))]
const SEQ_LEN: usize = 32;
#[cfg(test)]
const SEQ_LEN: usize = 16;

#[cfg(not(test))]
const D_HEAD: usize = 64;
#[cfg(test)]
const D_HEAD: usize = 16;

#[cfg(not(test))]
const K_SUBSPACE_LEN: usize = 8;
#[cfg(test)]
const K_SUBSPACE_LEN: usize = 4;

// ════════════════════════════════════════════════════════════════════
// TRAINING HYPERPARAMETERS
// ════════════════════════════════════════════════════════════════════

/// 60 steps. The spec asks for 100-500 steps under a 60-second wall
/// budget; at the spec dims (vocab=256, seq=32, d_head=64, k_sub=8),
/// V2 dominates cost — every train_step does:
///   * 2 SPSA forwards for V (cheap, 1 attn pass each)
///   * 2 SPSA forwards for lm_head (1 attn each)
///   * 4 forwards × 2 sides = 8 forwards for the mix block
///   * 28 forwards × 2 sides = 56 forwards for the dual covector
/// → ~70 V2 forwards / step, each ~1ms. ~5 min for 120 steps in
/// release. 60 steps lands ~2 min, which is above the aspirational 60s
/// budget but is what the spec dims actually buy. Reducing further
/// hides the V2 trajectory.
const TRAIN_STEPS: usize = 60;
const LR: f32 = 5e-3;
const FD_EPS: f32 = 1e-3; // central-diff step size
const SPSA_EPS: f32 = 1e-2; // SPSA perturbation scale (bigger because
                            // SPSA is high-variance — we want signal
                            // > rounding noise on a single direction)
const TEST_SEQS: usize = 8; // held-out sequences for perplexity report
const TRAIN_SEED: u64 = 0xA17_E0E_CAFE_BEEF;

// ════════════════════════════════════════════════════════════════════
// LCG (SplitMix64) — single source of randomness
// ════════════════════════════════════════════════════════════════════

#[derive(Clone)]
struct Lcg(u64);

impl Lcg {
    fn new(seed: u64) -> Self {
        // Avoid the bad zero state. SplitMix64 is fine on zero but
        // chained generators are cleaner with a non-zero starter.
        Self(seed | 1)
    }
    fn next_u64(&mut self) -> u64 {
        self.0 = self.0.wrapping_add(0x9E37_79B9_7F4A_7C15);
        let mut z = self.0;
        z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
        z = (z ^ (z >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
        z ^ (z >> 31)
    }
    /// Uniform f32 in [-1, 1).
    fn next_f32_signed(&mut self) -> f32 {
        let u = (self.next_u64() >> 40) as f32 / ((1u32 << 24) as f32);
        2.0 * u - 1.0
    }
    /// ±1 Bernoulli (used for SPSA perturbation directions).
    fn next_pm1(&mut self) -> f32 {
        if self.next_u64() & 1 == 0 {
            -1.0
        } else {
            1.0
        }
    }
    /// Token id in [0, VOCAB_SIZE).
    fn next_token(&mut self) -> u8 {
        ((self.next_u64() as usize) % VOCAB_SIZE) as u8
    }
}

// ════════════════════════════════════════════════════════════════════
// SYNTHETIC DATA — periodic char-level pattern with token-level noise
// ════════════════════════════════════════════════════════════════════

/// Generate one training sequence of length `SEQ_LEN`. Pattern: a
/// fixed period-7 base sequence (deterministic per-seed shift) with
/// independent noise injected at every position with probability
/// `noise_p`. The next-token signal lives in the period; the noise
/// rate sets the irreducible perplexity floor.
///
/// Why period 7 and noise 1/8: at noise probability p, an oracle-
/// correct model picks the periodic continuation with probability
/// `1 − p + p / 256` ≈ 0.875, giving cross-entropy
/// `≈ −[(1−p)·ln(1−p) + p·ln(p/255)]` ≈ `0.74 nats`, perplexity
/// ≈ `2.1`. Both V1 and V2 have to climb out of the uniform-distribution
/// floor of `ln(256) ≈ 5.55 nats` (perplexity 256) to demonstrate
/// learning. Anything between those two numbers is "the model picked
/// up the pattern but did not memorize it."
fn synth_sequence(rng: &mut Lcg, noise_p_x256: u32) -> Vec<u8> {
    // One per-sequence base shift gives the model a real head/tail
    // alignment problem (it can't just memorize "position 0 → token X");
    // it has to attend to the previous tokens to figure out the phase.
    let phase = (rng.next_u64() & 0x7) as u8; // 0..=7
    let base: [u8; 7] = [b'a', b'b', b'c', b'd', b'e', b'f', b'g'];
    let mut seq = Vec::with_capacity(SEQ_LEN);
    for i in 0..SEQ_LEN {
        let clean = base[((i as u8).wrapping_add(phase) as usize) % 7];
        // Bernoulli(noise_p_x256 / 256) noise → uniform-random byte.
        let r = rng.next_u64() & 0xFF;
        if (r as u32) < noise_p_x256 {
            seq.push(rng.next_token());
        } else {
            seq.push(clean);
        }
    }
    seq
}

/// Deterministic train + test split. `train_n` and `test_n` are
/// independently seeded so changing the train-set size doesn't alter
/// the held-out evaluation distribution.
fn build_dataset(train_n: usize, test_n: usize) -> (Vec<Vec<u8>>, Vec<Vec<u8>>) {
    let noise_p_x256 = 32; // 32/256 = 12.5% noise → easy but non-trivial
    let mut train_rng = Lcg::new(TRAIN_SEED);
    let mut test_rng = Lcg::new(TRAIN_SEED ^ 0xDEAD_BEEF_DEAD_BEEF);
    let train: Vec<_> = (0..train_n)
        .map(|_| synth_sequence(&mut train_rng, noise_p_x256))
        .collect();
    let test: Vec<_> = (0..test_n)
        .map(|_| synth_sequence(&mut test_rng, noise_p_x256))
        .collect();
    (train, test)
}

// ════════════════════════════════════════════════════════════════════
// POSITIONAL ENCODING — sinusoidal (no params, free of training cost)
// ════════════════════════════════════════════════════════════════════

/// Sinusoidal PE matrix `[SEQ_LEN, D_HEAD]` (Vaswani et al. 2017,
/// section 3.5). Cached once at startup so we don't recompute it
/// inside the inner loop.
fn build_sinusoidal_pe() -> Vec<f32> {
    let mut pe = vec![0.0_f32; SEQ_LEN * D_HEAD];
    for pos in 0..SEQ_LEN {
        for i in 0..D_HEAD {
            let denom = 10000.0_f32.powf((i / 2) as f32 * 2.0 / D_HEAD as f32);
            let arg = pos as f32 / denom;
            pe[pos * D_HEAD + i] = if i % 2 == 0 { arg.sin() } else { arg.cos() };
        }
    }
    pe
}

// ════════════════════════════════════════════════════════════════════
// PARAMETERS
// ════════════════════════════════════════════════════════════════════

/// All trainable parameters for one variant. V1 only uses
/// `embed_proj`, `v_proj`, `lm_head`. V2 additionally uses `mix` and
/// `dual_f`. We keep both fields in one struct so the SPSA step can
/// touch the same bytes for both variants and the comparison stays
/// apples-to-apples (same init, same data, same step count).
#[derive(Clone)]
struct Params {
    // Token embedding [VOCAB_SIZE, D_HEAD]. We don't train this — token
    // embeddings introduce another ~16K params and the toy model can
    // route everything through V/lm_head. Kept fixed-random so V1 and
    // V2 see the same input distribution.
    embed: Vec<f32>,
    // V projection [D_HEAD, D_HEAD]. SPSA-trained.
    v_proj: Vec<f32>,
    // lm_head [D_HEAD, VOCAB_SIZE]. SPSA-trained.
    lm_head: Vec<f32>,
    // V2-only: 2x2 mixing block. Per-parameter central-diff trained.
    mix: MixingBlock,
    // V2-only: dual covector. Held as f32 (so finite-diff has a smooth
    // surface) and cast to i64 inside the V2 forward. Per-parameter
    // central-diff trained.
    dual_f: Vec<f32>,
}

impl Params {
    fn init(rng: &mut Lcg) -> Self {
        let embed: Vec<f32> = (0..VOCAB_SIZE * D_HEAD)
            .map(|_| 0.1 * rng.next_f32_signed())
            .collect();
        let v_proj: Vec<f32> = (0..D_HEAD * D_HEAD)
            .map(|_| 0.1 * rng.next_f32_signed())
            .collect();
        let lm_head: Vec<f32> = (0..D_HEAD * VOCAB_SIZE)
            .map(|_| 0.1 * rng.next_f32_signed())
            .collect();
        // Mix init: small perturbation off the V1-equivalent identity
        // block. We need the block to be ASYMMETRIC at init (the
        // Lean invariant gates non-degeneracy), and starting at
        // exactly identity is safe (1≠0 ∧ 0≠1) but also gives V2 zero
        // signal advantage at step 0. Perturbing β,γ off zero by a
        // small random amount preserves asymmetry and lets the
        // gradient pull the off-diagonals.
        let mix = MixingBlock {
            alpha: 1.0,
            beta: 0.05 * rng.next_f32_signed(),
            gamma: 0.05 * rng.next_f32_signed(),
            delta: 1.0,
        };
        debug_assert!(mix.is_asymmetric_in_qk());
        // Dual init: small ±1-ish floats so cast-to-i64 gives a mix
        // of −1, 0, 1 entries (matching the V1 hardcoded all-ones
        // dual at the closest integer rounding once the signs settle).
        let dual_len = k_subsets(2, K_SUBSPACE_LEN).len(); // C(8,2)=28
        let dual_f: Vec<f32> = (0..dual_len)
            .map(|_| 0.5 + 0.3 * rng.next_f32_signed())
            .collect();
        Self {
            embed,
            v_proj,
            lm_head,
            mix,
            dual_f,
        }
    }
}

// ════════════════════════════════════════════════════════════════════
// FORWARD PATH — embed → V proj → attention → lm_head → CE loss
// ════════════════════════════════════════════════════════════════════

/// Lookup token embeddings + add sinusoidal PE → `[SEQ_LEN, D_HEAD]`.
fn embed_with_pe(tokens: &[u8], embed: &[f32], pe: &[f32]) -> Vec<f32> {
    debug_assert_eq!(tokens.len(), SEQ_LEN);
    let mut x = vec![0.0_f32; SEQ_LEN * D_HEAD];
    for t in 0..SEQ_LEN {
        let tok = tokens[t] as usize;
        let src = &embed[tok * D_HEAD..(tok + 1) * D_HEAD];
        let dst = &mut x[t * D_HEAD..(t + 1) * D_HEAD];
        for d in 0..D_HEAD {
            dst[d] = src[d] + pe[t * D_HEAD + d];
        }
    }
    x
}

/// Right-multiply `[SEQ_LEN, D_HEAD]` by `[D_HEAD, D_HEAD]` →
/// `[SEQ_LEN, D_HEAD]`. Tight inner loop, no allocations beyond the
/// output buffer.
fn matmul_seq_dxd(x: &[f32], w: &[f32]) -> Vec<f32> {
    let mut out = vec![0.0_f32; SEQ_LEN * D_HEAD];
    for t in 0..SEQ_LEN {
        let xrow = &x[t * D_HEAD..(t + 1) * D_HEAD];
        let orow = &mut out[t * D_HEAD..(t + 1) * D_HEAD];
        for d_out in 0..D_HEAD {
            let mut acc = 0.0_f32;
            for d_in in 0..D_HEAD {
                // w is row-major [D_HEAD, D_HEAD]; row d_in, col d_out.
                acc += xrow[d_in] * w[d_in * D_HEAD + d_out];
            }
            orow[d_out] = acc;
        }
    }
    out
}

/// Right-multiply `[SEQ_LEN, D_HEAD]` by `[D_HEAD, VOCAB_SIZE]` →
/// `[SEQ_LEN, VOCAB_SIZE]`. Same shape as `matmul_seq_dxd` but the
/// output dim is the vocab.
fn matmul_lm_head(x: &[f32], w: &[f32]) -> Vec<f32> {
    let mut out = vec![0.0_f32; SEQ_LEN * VOCAB_SIZE];
    for t in 0..SEQ_LEN {
        let xrow = &x[t * D_HEAD..(t + 1) * D_HEAD];
        let orow = &mut out[t * VOCAB_SIZE..(t + 1) * VOCAB_SIZE];
        for v in 0..VOCAB_SIZE {
            let mut acc = 0.0_f32;
            for d in 0..D_HEAD {
                acc += xrow[d] * w[d * VOCAB_SIZE + v];
            }
            orow[v] = acc;
        }
    }
    out
}

/// Causal-free, single-head attention dispatched on `variant`. We
/// don't apply a causal mask in this toy: the goal is to compare V1
/// vs V2 *as kernels*, and a mask would be applied identically to
/// both, which only obscures the comparison.
fn run_attention(variant: &Variant, params: &Params, x: &[f32]) -> Vec<f32> {
    // Q = K = X (no separate Q/K projection — the toy model does not
    // need one and removing it both halves the trainable param count
    // and prevents Q/K projection from masking small attention-kernel
    // differences).
    let v_x = matmul_seq_dxd(x, &params.v_proj);
    match variant {
        Variant::V1 => attention_via_softmax(x, x, &v_x, SEQ_LEN, D_HEAD),
        Variant::V2 => {
            // dual_f → i64. Round, not floor, to preserve the symmetric
            // sign behaviour around zero that the Lean amplitude expects.
            let dual_i: Vec<i64> = params.dual_f.iter().map(|&f| f.round() as i64).collect();
            attention_via_amplituhedron_v2(
                x,
                x,
                &v_x,
                SEQ_LEN,
                D_HEAD,
                &K_SUBSPACE_DIMS,
                params.mix,
                &dual_i,
            )
        }
    }
}

#[derive(Clone, Copy, Debug)]
enum Variant {
    V1,
    V2,
}

/// The fixed standing-wave dim selection. We pick the FIRST 8 dims
/// (0..8) so the toy is reproducible and the choice doesn't get
/// pulled into the parameter sweep. A real model would learn this or
/// derive it from RMSNorm energy — we don't need that subtlety here.
const K_SUBSPACE_DIMS: [usize; 8] = [0, 1, 2, 3, 4, 5, 6, 7];

/// Cross-entropy loss over the next-token shift. For `tokens[0..SEQ_LEN]`
/// we predict `tokens[1..SEQ_LEN]` from positions `0..SEQ_LEN-1`
/// (last position has no target). Returns mean nats per predicted
/// token.
fn cross_entropy(logits: &[f32], tokens: &[u8]) -> f32 {
    debug_assert_eq!(logits.len(), SEQ_LEN * VOCAB_SIZE);
    let mut total = 0.0_f64;
    let n_targets = SEQ_LEN - 1;
    for t in 0..n_targets {
        let row = &logits[t * VOCAB_SIZE..(t + 1) * VOCAB_SIZE];
        let tgt = tokens[t + 1] as usize;
        // log-softmax in a numerically stable way.
        let max = row.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
        let mut sum_exp = 0.0_f64;
        for &v in row.iter() {
            sum_exp += ((v - max) as f64).exp();
        }
        let log_z = sum_exp.ln() + max as f64;
        let log_p = row[tgt] as f64 - log_z;
        total += -log_p;
    }
    (total / n_targets as f64) as f32
}

/// Single forward pass: tokens → loss. Hot path.
fn forward_loss(variant: &Variant, params: &Params, pe: &[f32], tokens: &[u8]) -> f32 {
    let x = embed_with_pe(tokens, &params.embed, pe);
    let attn = run_attention(variant, params, &x);
    let logits = matmul_lm_head(&attn, &params.lm_head);
    cross_entropy(&logits, tokens)
}

/// Mean loss over a batch of sequences (SGD signal averages the
/// per-step gradient noise across `batch.len()` sequences).
fn batch_loss(variant: &Variant, params: &Params, pe: &[f32], batch: &[&[u8]]) -> f32 {
    let mut total = 0.0_f64;
    for tokens in batch {
        total += forward_loss(variant, params, pe, tokens) as f64;
    }
    (total / batch.len() as f64) as f32
}

// ════════════════════════════════════════════════════════════════════
// GRADIENT ESTIMATORS
// ════════════════════════════════════════════════════════════════════

/// Per-parameter central differences for the SMALL parameter sets
/// (mix block: 4 floats, dual: 28 floats). Returns the gradient.
fn central_diff_mix(
    variant: &Variant,
    params: &mut Params,
    pe: &[f32],
    batch: &[&[u8]],
    eps: f32,
) -> [f32; 4] {
    let mut g = [0.0_f32; 4];
    let original = params.mix;
    for i in 0..4 {
        // Pull/push one component out of `params.mix`.
        let plus = perturb_mix(original, i, eps);
        let minus = perturb_mix(original, i, -eps);
        params.mix = plus;
        let lp = batch_loss(variant, params, pe, batch);
        params.mix = minus;
        let lm = batch_loss(variant, params, pe, batch);
        g[i] = (lp - lm) / (2.0 * eps);
    }
    params.mix = original;
    g
}

fn perturb_mix(mut m: MixingBlock, idx: usize, delta: f32) -> MixingBlock {
    match idx {
        0 => m.alpha += delta,
        1 => m.beta += delta,
        2 => m.gamma += delta,
        3 => m.delta += delta,
        _ => unreachable!(),
    }
    m
}

fn central_diff_dual(
    variant: &Variant,
    params: &mut Params,
    pe: &[f32],
    batch: &[&[u8]],
    eps: f32,
) -> Vec<f32> {
    let n = params.dual_f.len();
    let mut g = vec![0.0_f32; n];
    for i in 0..n {
        let saved = params.dual_f[i];
        params.dual_f[i] = saved + eps;
        let lp = batch_loss(variant, params, pe, batch);
        params.dual_f[i] = saved - eps;
        let lm = batch_loss(variant, params, pe, batch);
        params.dual_f[i] = saved;
        g[i] = (lp - lm) / (2.0 * eps);
    }
    g
}

/// SPSA gradient estimator (Spall, "Multivariate Stochastic
/// Approximation Using a Simultaneous Perturbation Gradient
/// Approximation," IEEE TAC 1992). For an N-dimensional parameter
/// vector θ and Bernoulli ±1 perturbation Δ:
///
/// ```text
///   g_i  ≈  (L(θ + ε·Δ) − L(θ − ε·Δ)) / (2 · ε · Δ_i)
/// ```
///
/// Two forwards per gradient step regardless of N. Per-coordinate
/// estimates are noisy but unbiased; SGD averages out the noise over
/// many steps. The `Δ_i ∈ {−1, +1}` so `1/Δ_i = Δ_i`.
///
/// Used for V (4096 params) and lm_head (16384 params); per-param
/// central differences over those would need ~40K forwards per step
/// — way over the 60s wall budget for 100 steps.
fn spsa_grad(
    variant: &Variant,
    params: &mut Params,
    pe: &[f32],
    batch: &[&[u8]],
    eps: f32,
    rng: &mut Lcg,
    target: SpsaTarget,
) -> Vec<f32> {
    let n = match target {
        SpsaTarget::VProj => params.v_proj.len(),
        SpsaTarget::LmHead => params.lm_head.len(),
    };
    let perturbation: Vec<f32> = (0..n).map(|_| rng.next_pm1()).collect();

    // Save original.
    let saved: Vec<f32> = match target {
        SpsaTarget::VProj => params.v_proj.clone(),
        SpsaTarget::LmHead => params.lm_head.clone(),
    };

    // θ + ε·Δ
    {
        let dst = match target {
            SpsaTarget::VProj => &mut params.v_proj,
            SpsaTarget::LmHead => &mut params.lm_head,
        };
        for i in 0..n {
            dst[i] = saved[i] + eps * perturbation[i];
        }
    }
    let lp = batch_loss(variant, params, pe, batch);

    // θ − ε·Δ
    {
        let dst = match target {
            SpsaTarget::VProj => &mut params.v_proj,
            SpsaTarget::LmHead => &mut params.lm_head,
        };
        for i in 0..n {
            dst[i] = saved[i] - eps * perturbation[i];
        }
    }
    let lm = batch_loss(variant, params, pe, batch);

    // Restore.
    {
        let dst = match target {
            SpsaTarget::VProj => &mut params.v_proj,
            SpsaTarget::LmHead => &mut params.lm_head,
        };
        dst.copy_from_slice(&saved);
    }

    let denom = 2.0 * eps;
    let coeff = (lp - lm) / denom;
    perturbation.iter().map(|&d| coeff * d).collect()
}

#[derive(Clone, Copy)]
enum SpsaTarget {
    VProj,
    LmHead,
}

// ════════════════════════════════════════════════════════════════════
// TRAINING LOOP
// ════════════════════════════════════════════════════════════════════

/// Take one SGD step for one variant on one mini-batch. Returns the
/// pre-step loss (so we can log "loss BEFORE this step" = the loss
/// evaluated at the parameters that produced it).
fn train_step(
    variant: &Variant,
    params: &mut Params,
    pe: &[f32],
    batch: &[&[u8]],
    spsa_rng: &mut Lcg,
) -> f32 {
    let pre_loss = batch_loss(variant, params, pe, batch);

    // Big params — SPSA, one direction each, then SGD step.
    let g_v = spsa_grad(
        variant,
        params,
        pe,
        batch,
        SPSA_EPS,
        spsa_rng,
        SpsaTarget::VProj,
    );
    for i in 0..params.v_proj.len() {
        params.v_proj[i] -= LR * g_v[i];
    }
    let g_lm = spsa_grad(
        variant,
        params,
        pe,
        batch,
        SPSA_EPS,
        spsa_rng,
        SpsaTarget::LmHead,
    );
    for i in 0..params.lm_head.len() {
        params.lm_head[i] -= LR * g_lm[i];
    }

    // V2-only: train mix + dual via per-param central differences.
    if matches!(variant, Variant::V2) {
        let g_mix = central_diff_mix(variant, params, pe, batch, FD_EPS);
        params.mix.alpha -= LR * g_mix[0];
        params.mix.beta -= LR * g_mix[1];
        params.mix.gamma -= LR * g_mix[2];
        params.mix.delta -= LR * g_mix[3];

        let g_dual = central_diff_dual(variant, params, pe, batch, FD_EPS);
        for i in 0..params.dual_f.len() {
            params.dual_f[i] -= LR * g_dual[i];
        }

        // The Lean `learned_mix_invariant` gate. If a step ever lands
        // exactly on the symmetric subspace (α=β ∧ γ=δ), the V2
        // amplitude collapses to zero and every subsequent gradient
        // is zero too. Empirically it never happens with float
        // arithmetic on a non-degenerate dataset, but we guard it
        // explicitly so a regression in the optimizer is loud.
        assert!(
            params.mix.is_asymmetric_in_qk(),
            "MixingBlock collapsed to the symmetric subspace at step \
             — learned_mix_invariant violated; α={} β={} γ={} δ={}",
            params.mix.alpha,
            params.mix.beta,
            params.mix.gamma,
            params.mix.delta
        );
    }

    pre_loss
}

/// Convert mean-nats loss → perplexity (`exp(loss)`).
fn perplexity(loss: f32) -> f32 {
    (loss as f64).exp() as f32
}

// ════════════════════════════════════════════════════════════════════
// DRIVER
// ════════════════════════════════════════════════════════════════════

fn run_training(
    variant: Variant,
    init_params: &Params,
    pe: &[f32],
    train: &[Vec<u8>],
    test: &[Vec<u8>],
    n_steps: usize,
    spsa_seed: u64,
) -> TrainOutcome {
    let mut params = init_params.clone();
    let mut spsa_rng = Lcg::new(spsa_seed);
    // Mini-batch size 1: SGD with one sequence per step. SPSA already
    // injects enough variance that bigger batches buy little signal at
    // this scale, and the wall-clock budget prefers more steps over
    // bigger batches.
    let mut data_rng = Lcg::new(spsa_seed ^ 0x12345);

    let mut history = Vec::with_capacity(n_steps);
    for step in 0..n_steps {
        let idx = (data_rng.next_u64() as usize) % train.len();
        let batch_slice: &[&[u8]] = &[train[idx].as_slice()];
        let pre_loss = train_step(&variant, &mut params, pe, batch_slice, &mut spsa_rng);
        history.push(pre_loss);

        if step % 10 == 0 || step == n_steps - 1 {
            let asym = match variant {
                Variant::V1 => true, // V1 has no mix, vacuously fine
                Variant::V2 => params.mix.is_asymmetric_in_qk(),
            };
            println!(
                "  [{:?}] step {:>4}  loss={:.4}  ppl={:>8.2}  mix=[{:+.3},{:+.3},{:+.3},{:+.3}] asym={}",
                variant,
                step,
                pre_loss,
                perplexity(pre_loss),
                params.mix.alpha,
                params.mix.beta,
                params.mix.gamma,
                params.mix.delta,
                asym,
            );
        }
    }

    // Held-out test loss / perplexity.
    let test_refs: Vec<&[u8]> = test.iter().map(|s| s.as_slice()).collect();
    let test_loss = batch_loss(&variant, &params, pe, &test_refs);
    let asym_final = match variant {
        Variant::V1 => true,
        Variant::V2 => params.mix.is_asymmetric_in_qk(),
    };

    TrainOutcome {
        variant,
        history,
        final_params: params,
        test_loss,
        test_perplexity: perplexity(test_loss),
        asym_final,
    }
}

struct TrainOutcome {
    /// Retained for log-line clarity / future eval sweeps; intentionally
    /// not read by the main report (which already labels each block by
    /// variant manually). `#[allow]` keeps the build warning-free.
    #[allow(dead_code)]
    variant: Variant,
    history: Vec<f32>,
    final_params: Params,
    test_loss: f32,
    test_perplexity: f32,
    asym_final: bool,
}

fn main() {
    println!("┌──────────────────────────────────────────────────────────────────┐");
    println!("│ train_amp_v2 — Phase B amplituhedron-attention V2 trainer         │");
    println!(
        "│   vocab={}, seq_len={}, d_head={}, k_sub={}, dual_len={}        │",
        VOCAB_SIZE,
        SEQ_LEN,
        D_HEAD,
        K_SUBSPACE_LEN,
        k_subsets(2, K_SUBSPACE_LEN).len(),
    );
    println!(
        "│   steps={}, lr={}, fd_eps={}, spsa_eps={}                  │",
        TRAIN_STEPS, LR, FD_EPS, SPSA_EPS
    );
    println!("└──────────────────────────────────────────────────────────────────┘");

    let pe = build_sinusoidal_pe();
    let (train, test) = build_dataset(64, TEST_SEQS);
    println!(
        "dataset: {} train sequences, {} test sequences",
        train.len(),
        test.len()
    );

    // Single shared init: V1 and V2 see byte-identical embed/V/lm_head
    // initial weights. The IDENTITY-mix Phase A parity guarantees V2
    // step 0 == V1 step 0 EXCEPT for the small initial mix
    // perturbation (0.05 × signed-uniform). This keeps the comparison
    // honest — same starting loss within ~1%.
    let init_params = {
        let mut rng = Lcg::new(0x1234_5678_9ABC_DEF0);
        Params::init(&mut rng)
    };

    let t0 = std::time::Instant::now();
    println!("\n── V1 (softmax) ──");
    let v1 = run_training(
        Variant::V1,
        &init_params,
        &pe,
        &train,
        &test,
        TRAIN_STEPS,
        0xC0FFEE_C0FFEE,
    );
    let t_v1 = t0.elapsed();

    let t1 = std::time::Instant::now();
    println!("\n── V2 (amplituhedron + LearnedMix) ──");
    let v2 = run_training(
        Variant::V2,
        &init_params,
        &pe,
        &train,
        &test,
        TRAIN_STEPS,
        0xC0FFEE_C0FFEE, // same SPSA seed → same big-param trajectory at step 0
    );
    let t_v2 = t1.elapsed();

    // ── REPORT ────────────────────────────────────────────────────
    println!("\n┌──────────────────────────── RESULTS ────────────────────────────┐");
    println!(
        "│ V1 init train loss       {:>10.4}  ppl {:>10.2}",
        v1.history[0],
        perplexity(v1.history[0])
    );
    println!(
        "│ V1 final train loss      {:>10.4}  ppl {:>10.2}",
        v1.history.last().copied().unwrap(),
        perplexity(v1.history.last().copied().unwrap())
    );
    println!(
        "│ V1 test loss             {:>10.4}  ppl {:>10.2}",
        v1.test_loss, v1.test_perplexity
    );
    println!("│ V1 wall                  {:>10.2}s", t_v1.as_secs_f32());
    println!("│ ----------------------------------------------------------------- │");
    println!(
        "│ V2 init train loss       {:>10.4}  ppl {:>10.2}",
        v2.history[0],
        perplexity(v2.history[0])
    );
    println!(
        "│ V2 final train loss      {:>10.4}  ppl {:>10.2}",
        v2.history.last().copied().unwrap(),
        perplexity(v2.history.last().copied().unwrap())
    );
    println!(
        "│ V2 test loss             {:>10.4}  ppl {:>10.2}",
        v2.test_loss, v2.test_perplexity
    );
    println!("│ V2 wall                  {:>10.2}s", t_v2.as_secs_f32());
    println!("│ V2 mix asymmetric end?   {:>10}", v2.asym_final);
    println!("│ ----------------------------------------------------------------- │");
    let ratio = v2.test_perplexity / v1.test_perplexity;
    println!(
        "│ ppl ratio V2/V1          {:>10.4}  (<1 = V2 wins, >1 = V2 loses) │",
        ratio
    );
    println!("└─────────────────────────────────────────────────────────────────┘");

    println!("\nFinal V2 MixingBlock:");
    println!(
        "  α={:+.6}  β={:+.6}  γ={:+.6}  δ={:+.6}",
        v2.final_params.mix.alpha,
        v2.final_params.mix.beta,
        v2.final_params.mix.gamma,
        v2.final_params.mix.delta,
    );
    let dual_i: Vec<i64> = v2
        .final_params
        .dual_f
        .iter()
        .map(|&f| f.round() as i64)
        .collect();
    println!(
        "Final V2 dual covector (rounded i64, len={}):",
        dual_i.len()
    );
    println!("  {:?}", dual_i);
    println!("Final V2 dual covector (raw f32):");
    let dual_pretty: Vec<String> = v2
        .final_params
        .dual_f
        .iter()
        .map(|f| format!("{:+.3}", f))
        .collect();
    println!("  [{}]", dual_pretty.join(", "));

    let verdict = if v2.test_perplexity < v1.test_perplexity * 0.98 {
        "V2 WINS"
    } else if v2.test_perplexity > v1.test_perplexity * 1.02 {
        "V2 LOSES"
    } else {
        "V2 TIES"
    };
    println!("\nVerdict at this scale: {}", verdict);
    println!("  V1 final test perplexity: {:.4}", v1.test_perplexity);
    println!("  V2 final test perplexity: {:.4}", v2.test_perplexity);
}

// ════════════════════════════════════════════════════════════════════
// TESTS
// ════════════════════════════════════════════════════════════════════

#[cfg(test)]
mod tests {
    use super::*;

    /// Tiny config used by all tests so they finish in < 30s under
    /// `cargo test` (which builds in dev profile, 5-10× slower than
    /// release). The `main` binary uses the spec dims; tests exercise
    /// the same code paths on a smaller harness so the integration is
    /// what's verified, not the perplexity numbers.
    const TEST_STEPS: usize = 20;
    const LOSS_WINDOW: usize = 5;

    fn smoke_dataset() -> (Vec<Vec<u8>>, Vec<Vec<u8>>) {
        build_dataset(8, 2)
    }

    fn smoke_init() -> Params {
        let mut rng = Lcg::new(0xBADD_F00D);
        Params::init(&mut rng)
    }

    /// Sanity #1: the V1 training loop actually drives loss down. If
    /// this test ever fails, the SPSA / lm_head / V-proj plumbing is
    /// broken regardless of anything V2 does.
    #[test]
    fn loss_decreases_over_training_v1() {
        let pe = build_sinusoidal_pe();
        let (train, test) = smoke_dataset();
        let init = smoke_init();
        let outcome = run_training(
            Variant::V1,
            &init,
            &pe,
            &train,
            &test,
            TEST_STEPS,
            0xDEAD_BEEF,
        );
        // Compare the FIRST WINDOW of loss vs the LAST WINDOW (mean of
        // 5 each) to suppress single-sample SPSA noise. Strict
        // inequality on raw endpoints is too brittle for SPSA.
        let first: f32 = outcome.history[0..LOSS_WINDOW].iter().sum::<f32>() / LOSS_WINDOW as f32;
        let last: f32 = outcome.history[TEST_STEPS - LOSS_WINDOW..TEST_STEPS]
            .iter()
            .sum::<f32>()
            / LOSS_WINDOW as f32;
        assert!(
            last < first,
            "V1 loss did not decrease: first-window mean {first:.4} → \
             last-window mean {last:.4} over {TEST_STEPS} steps. \
             Training loop / SPSA gradient is broken."
        );
    }

    /// Sanity #2: V2 trains too. Same window-mean criterion as V1 so
    /// the SPSA noise floor doesn't poison the assertion. Failure
    /// here means the V2 attention is contributing zero gradient
    /// signal (i.e. the kernel is differentially flat in θ).
    #[test]
    fn loss_decreases_over_training_v2() {
        let pe = build_sinusoidal_pe();
        let (train, test) = smoke_dataset();
        let init = smoke_init();
        let outcome = run_training(
            Variant::V2,
            &init,
            &pe,
            &train,
            &test,
            TEST_STEPS,
            0xDEAD_BEEF,
        );
        let first: f32 = outcome.history[0..LOSS_WINDOW].iter().sum::<f32>() / LOSS_WINDOW as f32;
        let last: f32 = outcome.history[TEST_STEPS - LOSS_WINDOW..TEST_STEPS]
            .iter()
            .sum::<f32>()
            / LOSS_WINDOW as f32;
        assert!(
            last < first,
            "V2 loss did not decrease: first-window mean {first:.4} → \
             last-window mean {last:.4} over {TEST_STEPS} steps. \
             V2 attention is differentially flat or mix/dual gradient \
             estimator is wrong."
        );
        // Also pin the Lean invariant at the END.
        assert!(
            outcome.asym_final,
            "V2 final mix lost asymmetry — learned_mix_invariant fail"
        );
    }

    /// Sanity #3: the Lean `learned_mix_invariant` gate holds across
    /// the ENTIRE training trajectory, not just at endpoints. We
    /// re-run training and assert every recorded mix is asymmetric.
    /// (`train_step` panics on violation already, but this test
    /// double-checks by polling the field directly so a future change
    /// that drops the in-loop assert doesn't silently regress.)
    #[test]
    fn mixing_block_stays_asymmetric() {
        let pe = build_sinusoidal_pe();
        let (train, _test) = smoke_dataset();
        let mut params = smoke_init();
        let mut spsa_rng = Lcg::new(0xDEAD_BEEF);
        let mut data_rng = Lcg::new(0xDEAD_BEEF ^ 0x12345);

        for step in 0..20 {
            let idx = (data_rng.next_u64() as usize) % train.len();
            let batch: &[&[u8]] = &[train[idx].as_slice()];
            let _ = train_step(&Variant::V2, &mut params, &pe, batch, &mut spsa_rng);
            assert!(
                params.mix.is_asymmetric_in_qk(),
                "mix became symmetric at step {}: α={} β={} γ={} δ={}",
                step,
                params.mix.alpha,
                params.mix.beta,
                params.mix.gamma,
                params.mix.delta,
            );
        }
    }
}
